const CONFIG = {
  SUPABASE_URL: 'https://tzkvbtozhsrlmcpbrstp.supabase.co',
  SUPABASE_SERVICE_ROLE_KEY: 'ВСТАВЬ_SUPABASE_SERVICE_ROLE_KEY',
  YOOKASSA_SHOP_ID: '1299347',
  YOOKASSA_SECRET_KEY: 'ВСТАВЬ_СЕКРЕТНЫЙ_КЛЮЧ_ЮKASSA',
  RETURN_URL: 'https://app.primerkakoles.ru/cabinet?payment=return',
};

const packages = {
  pack_1: { generations: 1, amountRub: 60, title: '1 примерка' },
  pack_5: { generations: 5, amountRub: 199, title: '5 примерок' },
  pack_10: { generations: 10, amountRub: 349, title: '10 примерок' },
};

function jsonResponse(body, statusCode = 200) {
  return [{ json: { statusCode, ...body } }];
}

function hasPlaceholder(value) {
  return !value || String(value).includes('ВСТАВЬ_');
}

if (hasPlaceholder(CONFIG.SUPABASE_SERVICE_ROLE_KEY) || hasPlaceholder(CONFIG.YOOKASSA_SECRET_KEY)) {
  return jsonResponse({ error: 'n8n workflow is not configured: replace secret placeholders in Create YooKassa Payment node' }, 500);
}

const req = $input.first().json;
const headers = req.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';
if (!token) return jsonResponse({ error: 'Unauthorized' }, 401);

const body = req.body || {};
const packageCode = body.package_code;
const pack = packages[packageCode];
if (!pack) return jsonResponse({ error: 'Unknown package_code' }, 400);

let user;
try {
  user = await this.helpers.httpRequest({
    method: 'GET',
    url: `${CONFIG.SUPABASE_URL}/auth/v1/user`,
    headers: {
      apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${token}`,
    },
    json: true,
  });
} catch (error) {
  return jsonResponse({ error: 'Unauthorized' }, 401);
}

const users = await this.helpers.httpRequest({
  method: 'GET',
  url: `${CONFIG.SUPABASE_URL}/rest/v1/users?auth_user_id=eq.${user.id}&select=id,auth_user_id,email&limit=1`,
  headers: {
    apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
    Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
  },
  json: true,
});

const profile = Array.isArray(users) ? users[0] : null;
if (!profile) return jsonResponse({ error: 'Profile not found' }, 404);

const orderRows = await this.helpers.httpRequest({
  method: 'POST',
  url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders`,
  headers: {
    apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
    Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    Prefer: 'return=representation',
  },
  body: {
    auth_user_id: user.id,
    user_id: profile.id,
    package_code: packageCode,
    generations_count: pack.generations,
    amount_rub: pack.amountRub,
    currency: 'RUB',
    status: 'pending',
  },
  json: true,
});

const order = Array.isArray(orderRows) ? orderRows[0] : orderRows;
if (!order?.id) return jsonResponse({ error: 'Order was not created' }, 500);

const idempotenceKey = `web-order-${order.id}`;
const authBasic = Buffer.from(`${CONFIG.YOOKASSA_SHOP_ID}:${CONFIG.YOOKASSA_SECRET_KEY}`).toString('base64');
const amount = pack.amountRub.toFixed(2);

let payment;
try {
  payment = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.yookassa.ru/v3/payments',
    headers: {
      Authorization: `Basic ${authBasic}`,
      'Idempotence-Key': idempotenceKey,
      'Content-Type': 'application/json',
    },
    body: {
      amount: { value: amount, currency: 'RUB' },
      capture: true,
      confirmation: { type: 'redirect', return_url: CONFIG.RETURN_URL },
      description: `Примерка Колёс: ${pack.title}`,
      metadata: { order_id: order.id, package_code: packageCode, auth_user_id: user.id },
      receipt: {
        customer: { email: user.email || profile.email },
        items: [
          {
            description: `Пакет генераций: ${pack.title}`,
            quantity: 1,
            amount: { value: amount, currency: 'RUB' },
            vat_code: 1,
            payment_mode: 'full_payment',
            payment_subject: 'service',
          },
        ],
        tax_system_code: 2,
      },
    },
    json: true,
  });
} catch (error) {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?id=eq.${order.id}`,
    headers: {
      apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: { status: 'failed' },
    json: true,
  });
  return jsonResponse({ error: 'YooKassa payment creation failed' }, 502);
}

const confirmationUrl = payment.confirmation?.confirmation_url;
if (!payment.id || !confirmationUrl) return jsonResponse({ error: 'YooKassa did not return confirmation_url' }, 502);

await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?id=eq.${order.id}`,
  headers: {
    apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
    Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: {
    yookassa_payment_id: payment.id,
    confirmation_url: confirmationUrl,
  },
  json: true,
});

return jsonResponse({ order_id: order.id, confirmation_url: confirmationUrl }, 200);

const CONFIG = {
  SUPABASE_URL: 'https://tzkvbtozhsrlmcpbrstp.supabase.co',
  SUPABASE_SERVICE_ROLE_KEY: 'ВСТАВЬ_SUPABASE_SERVICE_ROLE_KEY',
};

function jsonResponse(body = { ok: true }, statusCode = 200) {
  return [{ json: { statusCode, ...body } }];
}

function hasPlaceholder(value) {
  return !value || String(value).includes('ВСТАВЬ_');
}

if (hasPlaceholder(CONFIG.SUPABASE_SERVICE_ROLE_KEY)) {
  return jsonResponse({ error: 'n8n workflow is not configured: replace Supabase placeholder in Process YooKassa Webhook node' }, 500);
}

const req = $input.first().json;
const event = req.body?.event;
const payment = req.body?.object;
if (!payment?.id) return jsonResponse();

const orderId = payment.metadata?.order_id;
let query = `yookassa_payment_id=eq.${payment.id}`;
if (orderId) query = `or=(yookassa_payment_id.eq.${payment.id},id.eq.${orderId})`;

const orders = await this.helpers.httpRequest({
  method: 'GET',
  url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?${query}&select=*`,
  headers: {
    apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
    Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
  },
  json: true,
});

const order = Array.isArray(orders) ? orders[0] : null;
if (!order) return jsonResponse({ ok: true, skipped: 'order_not_found' });

if (event === 'payment.succeeded') {
  const paidAmount = Number(payment.amount?.value || 0);
  const expectedAmount = Number(order.amount_rub || 0);
  if (payment.amount?.currency !== 'RUB' || paidAmount !== expectedAmount) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?id=eq.${order.id}`,
      headers: {
        apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
        Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
        'Content-Type': 'application/json',
      },
      body: { status: 'failed' },
      json: true,
    });
    return jsonResponse({ ok: true, skipped: 'amount_mismatch' });
  }

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?id=eq.${order.id}`,
    headers: {
      apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: { status: 'succeeded', yookassa_payment_id: payment.id },
    json: true,
  });

  await this.helpers.httpRequest({
    method: 'POST',
    url: `${CONFIG.SUPABASE_URL}/rest/v1/rpc/credit_generation_order`,
    headers: {
      apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: { p_order_id: order.id },
    json: true,
  });

  return jsonResponse({ ok: true, status: 'credited' });
}

if (event === 'payment.canceled') {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${CONFIG.SUPABASE_URL}/rest/v1/generation_orders?id=eq.${order.id}&credited_at=is.null`,
    headers: {
      apikey: CONFIG.SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${CONFIG.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: { status: 'canceled', yookassa_payment_id: payment.id },
    json: true,
  });
}

return jsonResponse();
